    /**
     * Creates a secure DocumentBuilderFactory that prevents XML bomb attacks
     * (billion laughs), XXE injection, and other XML-based attacks.
     */
    public static DocumentBuilderFactory createSecureDocumentBuilderFactory() throws ParserConfigurationException {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // Prevent XXE (XML External Entity) attacks
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

        // Disable external entities
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);

        // Disable external DTDs
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // Prevent entity expansion attacks (XML bomb / billion laughs)
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

        // Disable XInclude processing
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        // Set namespace awareness for SOAP processing
        factory.setNamespaceAware(true);

        return factory;
    }

    /**
     * Securely parses an XML input stream into a Document.
     */
    public Document secureParseXml(InputStream inputStream) throws Exception {
        // Read input with size limit to prevent memory exhaustion
        byte[] data = readWithSizeLimit(inputStream, MAX_PAYLOAD_SIZE);

        DocumentBuilderFactory factory = createSecureDocumentBuilderFactory();
        DocumentBuilder builder = factory.newDocumentBuilder();

        // Set a custom error handler that doesn't expose internal details
        builder.setErrorHandler(new SecureErrorHandler());

        Document document = builder.parse(new InputSource(new ByteArrayInputStream(data)));

        // Validate document depth to prevent deeply nested structures
        validateDocumentDepth(document.getDocumentElement(), 0);

        return document;
    }

    /**
     * Reads from an input stream with a maximum size limit.
     */
    private byte[] readWithSizeLimit(InputStream inputStream, int maxSize) throws IOException {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        byte[] chunk = new byte[8192];
        int totalRead = 0;
        int bytesRead;

        while ((bytesRead = inputStream.read(chunk)) != -1) {
            totalRead += bytesRead;
            if (totalRead > maxSize) {
                throw new IOException("Payload exceeds maximum allowed size of " + maxSize + " bytes");
            }
            buffer.write(chunk, 0, bytesRead);
        }

        return buffer.toByteArray();
    }

    /**
     * Validates that the XML document doesn't exceed maximum nesting depth.
     */
    private void validateDocumentDepth(Element element, int currentDepth) throws SAXException {
        if (currentDepth > MAX_ELEMENT_DEPTH) {
            throw new SAXException("XML document exceeds maximum allowed nesting depth of " + MAX_ELEMENT_DEPTH);
        }

        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                validateDocumentDepth((Element) child, currentDepth + 1);
            }
        }
    }

    /**
     * Processes the SOAP body and extracts data import records.
     */
    public ProcessingResult processSoapBody(Document document) throws Exception {
        ProcessingResult result = new ProcessingResult();

        // Navigate to SOAP Body
        NodeList bodyList = document.getElementsByTagNameNS(
                "http://schemas.xmlsoap.org/soap/envelope/", "Body");

        if (bodyList.getLength() == 0) {
            // Try SOAP 1.2 namespace
            bodyList = document.getElementsByTagNameNS(
                    "http://www.w3.org/2003/05/soap-envelope", "Body");
        }

        if (bodyList.getLength() == 0) {
            throw new SOAPException("No SOAP Body found in the message");
        }

        Element body = (Element) bodyList.item(0);

        // Process DataImportRequest
        NodeList importRequests = body.getElementsByTagName("DataImportRequest");
        if (importRequests.getLength() == 0) {
            importRequests = body.getElementsByTagName("*");
            for (int i = 0; i < importRequests.getLength(); i++) {
                Element el = (Element) importRequests.item(i);
                if (el.getLocalName() != null && el.getLocalName().equals("DataImportRequest")) {
                    processImportRequest(el, result);
                    return result;
                }
            }
            throw new SOAPException("No DataImportRequest element found");
        }

        for (int i = 0; i < importRequests.getLength(); i++) {
            processImportRequest((Element) importRequests.item(i), result);
        }

        return result;
    }

    /**
     * Processes a single DataImportRequest element with nested entities.
     */
    private void processImportRequest(Element importRequest, ProcessingResult result) {
        String batchId = getElementText(importRequest, "BatchId");
        String entityType = getElementText(importRequest, "EntityType");
        String sourceSystem = getElementText(importRequest, "SourceSystem");

        if (batchId == null || batchId.isEmpty()) {
            batchId = UUID.randomUUID().toString();
        }

        result.setBatchId(batchId);
        result.setEntityType(entityType);

        LOGGER.info("Processing import request - BatchId: " + batchId +
                ", EntityType: " + entityType + ", Source: " + sourceSystem);

        // Process Records container
        NodeList recordsContainers = importRequest.getElementsByTagName("Records");
        if (recordsContainers.getLength() > 0) {
            Element recordsContainer = (Element) recordsContainers.item(0);
            NodeList records = recordsContainer.getElementsByTagName("Record");

            for (int i = 0; i < records.getLength(); i++) {
                try {
                    Map<String, String> recordData = processRecord((Element) records.item(i));
                    result.addSuccessRecord(recordData);
                } catch (Exception e) {
                    result.addFailedRecord(i, e.getMessage());
                    LOGGER.log(Level.WARNING, "Failed to process record " + i, e);
                }
            }
        }

        // Process nested entity relationships
        NodeList relationships = importRequest.getElementsByTagName("Relationships");
        if (relationships.getLength() > 0) {
            processRelationships((Element) relationships.item(0), result);
        }

        // Store imported data
        importedData.put(batchId, result.getSuccessRecords());
    }

    /**
     * Processes a single Record element, extracting all fields including nested structures.
     */
    private Map<String, String> processRecord(Element record) {
        Map<String, String> data = new LinkedHashMap<>();

        // Extract record ID
        String recordId = record.getAttribute("id");
        if (recordId != null && !recordId.isEmpty()) {
            data.put("_recordId", sanitizeValue(recordId));
        }

        // Process all child elements as fields
        NodeList children = record.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element fieldElement = (Element) child;
                String fieldName = fieldElement.getLocalName() != null ?
                        fieldElement.getLocalName() : fieldElement.getTagName();

                // Handle nested complex fields
                if (hasChildElements(fieldElement)) {
                    processNestedField(fieldElement, fieldName, data);
                } else {
                    String value = sanitizeValue(fieldElement.getTextContent().trim());
                    data.put(fieldName, value);
                }
            }
        }

        return data;
    }

    /**
     * Processes nested field structures (e.g., Address with Street, City, etc.)
     */
    private void processNestedField(Element element, String prefix, Map<String, String> data) {
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) child;
                String childName = childElement.getLocalName() != null ?
                        childElement.getLocalName() : childElement.getTagName();
                String fullPath = prefix + "." + childName;

                if (hasChildElements(childElement)) {
                    processNestedField(childElement, fullPath, data);
                } else {
                    String value = sanitizeValue(childElement.getTextContent().trim());
                    data.put(fullPath, value);
                }
            }
        }
    }

    /**
     * Processes relationship definitions between entities.
     */
    private void processRelationships(Element relationships, ProcessingResult result) {
        NodeList relationshipList = relationships.getElementsByTagName("Relationship");
        for (int i = 0; i < relationshipList.getLength(); i++) {
            Element rel = (Element) relationshipList.item(i);
            String type = getElementText(rel, "Type");
            String sourceId = getElementText(rel, "SourceId");
            String targetId = getElementText(rel, "TargetId");
            String targetEntity = getElementText(rel, "TargetEntity");

            Map<String, String> relData = new LinkedHashMap<>();
            relData.put("_type", "relationship");
            relData.put("relationshipType", sanitizeValue(type));
            relData.put("sourceId", sanitizeValue(sourceId));
            relData.put("targetId", sanitizeValue(targetId));
            relData.put("targetEntity", sanitizeValue(targetEntity));

            // Process nested attributes of the relationship
            NodeList attributes = rel.getElementsByTagName("Attributes");
            if (attributes.getLength() > 0) {
                processNestedField((Element) attributes.item(0), "attributes", relData);
            }

            result.addRelationship(relData);
        }
    }

    /**
     * Sanitizes a string value to prevent injection attacks.
     */
    private String sanitizeValue(String value) {
        if (value == null) return null;
        // Remove control characters except tab, newline, carriage return
        return value.replaceAll("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]", "")
                .trim();
    }

    private boolean hasChildElements(Element element) {
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                return true;
            }
        }
        return false;
    }

    private String getElementText(Element parent, String tagName) {
        NodeList elements = parent.getElementsByTagName(tagName);
        if (elements.getLength() > 0) {
            return elements.item(0).getTextContent().trim();
        }
        return null;
    }

    /**
     * Builds a SOAP response document.
     */
    public String buildSoapResponse(ProcessingResult result) throws Exception {
        DocumentBuilderFactory factory = createSecureDocumentBuilderFactory();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.newDocument();

        // Create SOAP Envelope
        Element envelope = doc.createElementNS(
                "http://schemas.xmlsoap.org/soap/envelope/", "soap:Envelope");
        doc.appendChild(envelope);

        // Create SOAP Body
        Element body = doc.createElementNS(
                "http://schemas.xmlsoap.org/soap/envelope/", "soap:Body");
        envelope.appendChild(body);

        // Create Response
        Element response = doc.createElement("DataImportResponse");
        body.appendChild(response);

        // Batch ID
        Element batchIdEl = doc.createElement("BatchId");
        batchIdEl.setTextContent(result.getBatchId());
        response.appendChild(batchIdEl);

        // Status
        Element statusEl = doc.createElement("Status");
        statusEl.setTextContent(result.getFailedRecords().isEmpty() ? "SUCCESS" : "PARTIAL_SUCCESS");
        response.appendChild(statusEl);

        // Summary
        Element summary = doc.createElement("Summary");
        response.appendChild(summary);

        Element totalEl = doc.createElement("TotalRecords");
        totalEl.setTextContent(String.valueOf(
                result.getSuccessRecords().size() + result.getFailedRecords().size()));
        summary.appendChild(totalEl);

        Element successEl = doc.createElement("SuccessCount");
        successEl.setTextContent(String.valueOf(result.getSuccessRecords().size()));
        summary.appendChild(successEl);

        Element failedEl = doc.createElement("FailedCount");
        failedEl.setTextContent(String.valueOf(result.getFailedRecords().size()));
        summary.appendChild(failedEl);

        Element relEl = doc.createElement("RelationshipsProcessed");
        relEl.setTextContent(String.valueOf(result.getRelationships().size()));
        summary.appendChild(relEl);

        // Failed records details
        if (!result.getFailedRecords().isEmpty()) {
            Element errors = doc.createElement("Errors");
            response.appendChild(errors);

            for (Map.Entry<Integer, String> entry : result.getFailedRecords().entrySet()) {
                Element error = doc.createElement("Error");
                error.setAttribute("recordIndex", String.valueOf(entry.getKey()));
                error.setTextContent(entry.getValue());
                errors.appendChild(error);
            }
        }

        // Serialize to string
        TransformerFactory tf = TransformerFactory.newInstance();
        tf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        tf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        tf.setAttribute(XMLConstants.ACCESS_EXTERNAL_STYLESHEET, "");

        Transformer transformer = tf.newTransformer();
        transformer.setOutputProperty(javax.xml.transform.OutputKeys.INDENT, "yes");
        transformer.setOutputProperty(javax.xml.transform.OutputKeys.ENCODING, "UTF-8");

        StringWriter writer = new StringWriter();
        transformer.transform(new DOMSource(doc), new StreamResult(writer));
        return writer.toString();
    }

    /**
     * Builds a SOAP Fault response.
     */
    public String buildSoapFault(String faultCode, String faultString) throws Exception {
        DocumentBuilderFactory factory = createSecureDocumentBuilderFactory();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.newDocument();

        Element envelope = doc.createElementNS(
                "http://schemas.xmlsoap.org/soap/envelope/", "soap:Envelope");
        doc.appendChild(envelope);

        Element body = doc.createElementNS(
                "http://schemas.xmlsoap.org/soap/envelope/", "soap:Body");
        envelope.appendChild(body);

        Element fault = doc.createElementNS(
                "http://schemas.xmlsoap.org/soap/envelope/", "soap:Fault");
        body.appendChild(fault);

        Element faultCodeEl = doc.createElement("faultcode");
        faultCodeEl.setTextContent(faultCode);
        fault.appendChild(faultCodeEl);

        Element faultStringEl = doc.createElement("faultstring");
        faultStringEl.setTextContent(faultString);
        fault.appendChild(faultStringEl);

        TransformerFactory tf = TransformerFactory.newInstance();
        tf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        tf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        tf.setAttribute(XMLConstants.ACCESS_EXTERNAL_STYLESHEET, "");

        Transformer transformer = tf.newTransformer();
        transformer.setOutputProperty(javax.xml.transform.OutputKeys.INDENT, "yes");
        transformer.setOutputProperty(javax.xml.transform.OutputKeys.ENCODING, "UTF-8");

        StringWriter writer = new StringWriter();
        transformer.transform(new DOMSource(doc), new StreamResult(writer));
        return writer.toString();
    }

