    /**
     * HTTP Handler for SOAP requests.
     */
    static class SoapHandler implements HttpHandler {
        private final SecureSoapService service;

        SoapHandler(SecureSoapService service) {
            this.service = service;
        }

        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
                String fault;
                try {
                    fault = service.buildSoapFault("soap:Client", "Only POST method is supported");
                } catch (Exception e) {
                    fault = "<error>Method not allowed</error>";
                }
                sendResponse(exchange, 405, fault);
                return;
            }

            // Validate Content-Type
            String contentType = exchange.getRequestHeaders().getFirst("Content-Type");
            if (contentType == null ||
                    (!contentType.contains("text/xml") && !contentType.contains("application/soap+xml"))) {
                String fault;
                try {
                    fault = service.buildSoapFault("soap:Client", "Invalid Content-Type. Expected text/xml or application/soap+xml");
                } catch (Exception e) {
                    fault = "<error>Invalid content type</error>";
                }
                sendResponse(exchange, 415, fault);
                return;
            }

            try {
                // Securely parse the incoming SOAP XML
                Document document = service.secureParseXml(exchange.getRequestBody());

                // Process the SOAP body
                ProcessingResult result = service.processSoapBody(document);

                // Build and send response
                String response = service.buildSoapResponse(result);
                sendResponse(exchange, 200, response);

                LOGGER.info("Successfully processed batch: " + result.getBatchId() +
                        " - " + result.getSuccessRecords().size() + " records imported");

            } catch (SAXException e) {
                LOGGER.log(Level.SEVERE, "XML parsing error (possible attack detected)", e);
                String fault;
                try {
                    fault = service.buildSoapFault("soap:Client",
                            "Invalid XML document: " + e.getMessage());
                } catch (Exception ex) {
                    fault = "<error>XML parsing error</error>";
                }
                sendResponse(exchange, 400, fault);

            } catch (IOException e) {
                LOGGER.log(Level.SEVERE, "IO error processing request", e);
                String fault;
                try {
                    fault = service.buildSoapFault("soap:Client", e.getMessage());
                } catch (Exception ex) {
                    fault = "<error>IO error</error>";
                }
                sendResponse(exchange, 400, fault);

            } catch (SOAPException e) {
                LOGGER.log(Level.WARNING, "SOAP processing error", e);
                String fault;
                try {
                    fault = service.buildSoapFault("soap:Client", e.getMessage());
                } catch (Exception ex) {
                    fault = "<error>SOAP processing error</error>";
                }
                sendResponse(exchange, 400, fault);

            } catch (Exception e) {
                LOGGER.log(Level.SEVERE, "Unexpected error processing request", e);
                String fault;
                try {
                    fault = service.buildSoapFault("soap:Server",
                            "Internal server error");
                } catch (Exception ex) {
                    fault = "<error>Internal server error</error>";
                }
                sendResponse(exchange, 500, fault);
            }
        }

        private void sendResponse(HttpExchange exchange, int statusCode, String response) throws IOException {
            byte[] responseBytes = response.getBytes("UTF-8");
            exchange.getResponseHeaders().set("Content-Type", "text/xml; charset=UTF-8");
            exchange.sendResponseHeaders(statusCode, responseBytes.length);
            try (OutputStream os = exchange.getResponseBody()) {
                os.write(responseBytes);
            }
        }
    }

    /**
     * Custom SAX error handler that prevents information leakage.
     */
    static class SecureErrorHandler implements org.xml.sax.ErrorHandler {
        @Override
        public void warning(org.xml.sax.SAXParseException exception) throws SAXException {
            LOGGER.warning("XML Parse Warning: " + exception.getMessage());
        }

        @Override
        public void error(org.xml.sax.SAXParseException exception) throws SAXException {
            LOGGER.severe("XML Parse Error: " + exception.getMessage());
            throw new SAXException("XML document is not well-formed");
        }

        @Override
        public void fatalError(org.xml.sax.SAXParseException exception) throws SAXException {
            LOGGER.severe("XML Fatal Parse Error: " + exception.getMessage());
            throw new SAXException("XML document contains fatal errors");
        }
    }

    /**
     * Holds the results of processing a data import request.
     */
    static class ProcessingResult {
        private String batchId;
        private String entityType;
        private final List<Map<String, String>> successRecords = new ArrayList<>();
        private final Map<Integer, String> failedRecords = new LinkedHashMap<>();
        private final List<Map<String, String>> relationships = new ArrayList<>();

        public String getBatchId() { return batchId; }
        public void setBatchId(String batchId) { this.batchId = batchId; }

        public String getEntityType() { return entityType; }
        public void setEntityType(String entityType) { this.entityType = entityType; }

        public List<Map<String, String>> getSuccessRecords() { return successRecords; }
        public Map<Integer, String> getFailedRecords() { return failedRecords; }
        public List<Map<String, String>> getRelationships() { return relationships; }

        public void addSuccessRecord(Map<String, String> record) { successRecords.add(record); }
        public void addFailedRecord(int index, String reason) { failedRecords.put(index, reason); }
        public void addRelationship(Map<String, String> relationship) { relationships.add(relationship); }
    }
